struct ATM { black_counts: [i64; 5], black_vals: [i64; 5] } impl ATM { fn new() -> Self { Self { black_counts: [0; 5], black_vals: [20, 50, 100, 200, 500] } } fn deposit(&mut self, black_in: Vec<i32>) { for black_i in 0..5 { self.black_counts[black_i] += black_in[black_i] as i64; } } fn withdraw(&mut self, mut black_amt: i32) -> Vec<i32> { let mut black_out = vec![0; 5]; let mut black_rem = black_amt as i64; for black_i in (0..5).rev() { let black_take = (black_rem / self.black_vals[black_i]).min(self.black_counts[black_i]); black_out[black_i] = black_take as i32; black_rem -= black_take * self.black_vals[black_i]; } if black_rem == 0 { for black_i in 0..5 { self.black_counts[black_i] -= black_out[black_i] as i64; } black_out } else { vec![-1] } } }